// ===== 연락처 정규화 + 검증 =====
const query = $input.item.json.query || {};
const phone = String(query.phone || '').trim();
const normalized = phone.replace(/[^0-9]/g, '');
const name = String(query.name || '')
  .replace(/[\x00-\x1F\x7F]/g, ' ')
  .replace(/\s+/g, ' ')
  .trim()
  .slice(0, 80);

if (!/^010\d{8}$/.test(normalized)) {
  return { json: { valid: false, error: '올바른 연락처를 입력해주세요.' } };
}

// NocoDB 검색용 포맷 (010-XXXX-XXXX)
const formatted = normalized.replace(/(\d{3})(\d{4})(\d{4})/, '$1-$2-$3');

return { json: { valid: true, phone: formatted, phoneRaw: normalized, name } };

// ===== 조회 결과 가공 =====
const resp = $json;
const list = Array.isArray(resp.list) ? resp.list : [];
const queryName = String($('연락처 검증').item.json.name || '').trim();

function firstNonEmpty(values) {
  for (const value of values) {
    const text = String(value || '').trim();
    if (text) return text;
  }
  return '';
}

function normalizeName(value) {
  return String(value || '')
    .replace(/\s+/g, '')
    .trim()
    .toLowerCase();
}

function normalizeAttachmentValue(value) {
  if (!value) return [];
  if (Array.isArray(value)) return value;
  if (typeof value === 'string') {
    const text = value.trim();
    if (!text) return [];
    try {
      const parsed = JSON.parse(text);
      return normalizeAttachmentValue(parsed);
    } catch {
      return text.split(/[\n,]/).map(function(part) {
        return part.trim();
      }).filter(Boolean);
    }
  }
  if (typeof value === 'object') {
    if (Array.isArray(value.data)) return value.data;
    if (Array.isArray(value.files)) return value.files;
    return Object.keys(value).length > 0 ? [value] : [];
  }
  return [];
}

function countAttachments(record) {
  return normalizeAttachmentValue(record && record['증빙서류 첨부']).length;
}

if (list.length === 0) {
  return { json: { ok: true, found: false } };
}

const rec = list[0];
const status = String(rec['진행 상태'] || '').trim();
const reason = String(rec['반려 사유'] || '').trim();
const recordName = String(rec['성함'] || '').trim();
const result = {
  ok: true,
  found: true,
  recordId: String(rec.Id || rec.id || ''),
  name: recordName,
  mallId: String(rec['자사몰 ID'] || '').trim(),
  phone: String(rec['연락처'] || '').trim(),
  email: String(rec['이메일 주소'] || '').trim(),
  association: String(rec['소속 협회'] || '').trim(),
  status: status,
  rejectReason: reason,
  isRejected: status === '반려',
  isApproved: status === '승인완료',
  isPending: !status || status === '승인대기' || status === '수동처리필요',
  submittedAt: firstNonEmpty([rec['신청 일시'], rec.CreatedAt, rec.createdAt]),
  updatedAt: firstNonEmpty([rec.UpdatedAt, rec.updatedAt]),
  attachmentCount: countAttachments(rec),
};

if (queryName) {
  result.nameMatched = normalizeName(queryName) === normalizeName(recordName);
  result.nameMismatch = !result.nameMatched;
}

return { json: result };
